import React from 'react';
import { Project } from '../types';

interface ProjectCardProps {
  project: Project;
  index?: number;
}

const ProjectCard: React.FC<ProjectCardProps> = ({ project, index }) => {
  const { title, thumbnail } = project;
  const displayTitle = typeof index === 'number'
    ? `${String(index + 1).padStart(2, '0')} | ${title}`
    : title;

  return (
    <div className="project-card border-none bg-transparent">
      {/* smaller title above the thumbnail */}
      <h2 className="text-xs font-mono uppercase tracking-widest mb-2">
        {displayTitle}
      </h2>

      {/* 16:9 box — light gray placeholder if no thumbnail, otherwise use thumbnail as background */}
      <div
        className="w-full overflow-hidden"
        style={{ position: 'relative', paddingTop: '56.25%', backgroundColor: '#e6e6e6' }} // 56.25% = 16:9
      >
        {thumbnail ? (
          <div
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              backgroundImage: `url(${thumbnail})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
            }}
          />
        ) : null}
      </div>
    </div>
  );
};

export default ProjectCard;
